/**
 * Tensor naming convention shared between the Rust crate and this shim.
 *
 * Per-layer (L is the 0-indexed transformer block):
 *   blk_L_attn_norm_weight
 *   blk_L_attn_q_weight
 *   blk_L_attn_k_weight
 *   blk_L_attn_v_weight
 *   blk_L_attn_output_weight
 *   blk_L_ffn_norm_weight
 *   blk_L_ffn_gate_weight
 *   blk_L_ffn_up_weight
 *   blk_L_ffn_down_weight
 *
 * Resident (load once at open, never evict):
 *   token_embd_weight
 *   output_norm_weight
 *   output_weight   (optional — tied embeddings models omit it)
 */

/** Per-layer tensor suffixes, in canonical order. Nine per layer. */
export const PER_LAYER_TENSOR_SUFFIXES = Object.freeze([
  'attn_norm_weight',
  'attn_q_weight',
  'attn_k_weight',
  'attn_v_weight',
  'attn_output_weight',
  'ffn_norm_weight',
  'ffn_gate_weight',
  'ffn_up_weight',
  'ffn_down_weight',
] as const);

/**
 * Names that are loaded once at open and never evicted, in priority order.
 * `output_weight` is optional — tied-embedding models reuse `token_embd_weight`.
 */
export const RESIDENT_TENSOR_NAMES = Object.freeze([
  'token_embd_weight',
  'output_norm_weight',
  'output_weight',
] as const);

/** Build the 9 canonical tensor names for a transformer block. */
export function tensorNamesForLayer(layerIdx: number): string[] {
  if (!Number.isInteger(layerIdx) || layerIdx < 0) {
    throw new Error(`tensorNamesForLayer: layerIdx must be a non-negative integer, got ${layerIdx}`);
  }
  return PER_LAYER_TENSOR_SUFFIXES.map((suffix) => `blk_${layerIdx}_${suffix}`);
}
